// ============================================================
// Calculate cost & check message limits against Airtable
// ============================================================
const input = $input.first().json;

if (!input.customer_id || !input.tenant) {
  throw new Error('Missing customer_id or tenant');
}

// Model pricing (USD per 1M tokens) — convert to EGP
const USD_TO_EGP = 49;
const pricing = {
  'anthropic/claude-haiku-4.5':    { input: 1.00,  output: 5.00 },
  'anthropic/claude-sonnet-4.5':   { input: 3.00,  output: 15.00 },
  'anthropic/claude-opus-4.7':     { input: 15.00, output: 75.00 },
  'openai/gpt-4o':                 { input: 2.50,  output: 10.00 },
  'openai/gpt-4o-mini':            { input: 0.15,  output: 0.60 },
  'google/gemini-2.0-flash':       { input: 0.10,  output: 0.40 }
};

const model = input.model || 'anthropic/claude-sonnet-4.5';
const inputTokens = parseInt(input.input_tokens || 0);
const outputTokens = parseInt(input.output_tokens || 0);

const modelPricing = pricing[model] || pricing['anthropic/claude-sonnet-4.5'];
const costUsd = ((inputTokens * modelPricing.input) + (outputTokens * modelPricing.output)) / 1_000_000;
const costEgp = +(costUsd * USD_TO_EGP).toFixed(4);

// Plan-based message limits
const planLimits = {
  starter:    5000,
  business:   11000,
  enterprise: 20000
};

const tenantPlan = (input.tenant.plan_tier || input.tenant.plan_id || 'starter').toLowerCase();
const messagesLimit = planLimits[tenantPlan] || planLimits.starter;

return {
  json: {
    tenant_business_name: input.tenant.business_name,
    tenant_order_id: input.tenant.order_id,
    customer_id: input.customer_id,
    customer_name: input.customer_name || '',
    customer_phone: input.customer_phone || '',
    plan_id: tenantPlan,
    messages_limit: messagesLimit,
    model: model,
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    cost_usd: +costUsd.toFixed(6),
    cost_egp: costEgp,
    operation_type: input.operation_type || 'chat',
    timestamp: new Date().toISOString()
  }
};

// ============================================================
// Check if customer exists in quota table, calculate remaining
// ============================================================
const existing = $input.all();
const calc = $('CALCULATE_COST_LOGIC').first().json;

if (existing.length > 0 && existing[0].json && existing[0].json.id) {
  // Existing record
  const record = existing[0].json;
  const fields = record.fields || {};
  const currentMessages = parseInt(fields.messages_used || 0);
  const currentCost = parseFloat(fields.total_cost_egp || 0);

  const newMessageCount = currentMessages + 1;
  const newCost = +(currentCost + calc.cost_egp).toFixed(4);
  const remaining = calc.messages_limit - newMessageCount;
  const limitExceeded = newMessageCount > calc.messages_limit;

  return {
    json: {
      ...calc,
      airtable_record_id: record.id,
      is_new_quota_record: false,
      messages_used: newMessageCount,
      total_cost_egp: newCost,
      messages_remaining: Math.max(0, remaining),
      limit_exceeded: limitExceeded,
      action: limitExceeded ? 'block' : 'allow'
    }
  };
} else {
  // New customer — create record
  return {
    json: {
      ...calc,
      airtable_record_id: '',
      is_new_quota_record: true,
      messages_used: 1,
      total_cost_egp: calc.cost_egp,
      messages_remaining: calc.messages_limit - 1,
      limit_exceeded: false,
      action: 'allow'
    }
  };
}

const input = $input.first().json;
return {
  json: {
    success: true,
    customer_id: input.customer_id,
    cost_egp: input.cost_egp,
    messages_used: input.messages_used,
    messages_remaining: input.messages_remaining,
    limit_exceeded: input.limit_exceeded,
    action: input.action,
    message: input.limit_exceeded 
      ? `وصلت للحد الأقصى من الرسائل (${input.messages_limit}). تواصل مع ${input.tenant_business_name} للاستفسار.`
      : 'تم تحديث الـ quota بنجاح'
  }
};
